#!/usr/bin/env node
/**
 * scripts/qa/generate-phase-tests.mjs -- Phase 144: QA Ladder V2
 *
 * Reads the enriched phase registry and generates:
 *   1. Playwright domain journey tests (apps/web/e2e/domain-journeys/)
 *   2. RPC trace replay tests (apps/api/tests/rpc-replay/)
 *   3. Restart resilience tests (apps/api/tests/restart-resilience/)
 *
 * Usage:
 *   node scripts/qa/generate-phase-tests.mjs [--dry-run] [--phases 139-144] [--domain clinical]
 *
 * Generated files are deterministic and re-runnable.
 * DO NOT EDIT generated files -- regenerate instead.
 */

import {
  readFileSync,
  writeFileSync,
  mkdirSync,
  existsSync,
  readdirSync,
  unlinkSync,
} from 'node:fs';
import { resolve, join } from 'node:path';
import { buildRegistry } from './phase-registry.mjs';

const ROOT = process.cwd();
const E2E_DIR = resolve(ROOT, 'apps/web/e2e/domain-journeys');
const RPC_DIR = resolve(ROOT, 'apps/api/tests/rpc-replay');
const RESTART_DIR = resolve(ROOT, 'apps/api/tests/restart-resilience');
const GOLDEN_TRACE = resolve(ROOT, 'apps/api/tests/fixtures/rpc-golden-trace.json');

const args = process.argv.slice(2);
const DRY_RUN = args.includes('--dry-run');
const phaseRangeArg = args.find((a) => /^\d+-\d+$/.test(a)) || args[args.indexOf('--phases') + 1];
const domainFilter = args[args.indexOf('--domain') + 1];

// -- Helpers --

function safeId(str) {
  return str.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
}

function cleanDir(dir, prefix) {
  if (!existsSync(dir)) return;
  for (const f of readdirSync(dir)) {
    if (f.startsWith(prefix)) {
      unlinkSync(join(dir, f));
    }
  }
}

// -- Route Classification --

/** Routes that are safe to GET without auth (health, ready, etc.) */
const PUBLIC_ROUTES = new Set(['/health', '/ready', '/vista/ping']);

/** Routes requiring clinician session */
function isClinician(route) {
  return (
    route.startsWith('/vista/') ||
    route.startsWith('/cprs') ||
    route.startsWith('/scheduling/') ||
    route.startsWith('/rcm/') ||
    route.startsWith('/imaging/') ||
    route.startsWith('/analytics/') ||
    route.startsWith('/admin/')
  );
}

/** Routes requiring portal session */
function isPortal(route) {
  return route.startsWith('/portal/') || route.startsWith('/intake/');
}

// -- Playwright Journey Generator --

function generatePlaywrightJourney(domain, phases) {
  const lines = [];
  lines.push(`/**`);
  lines.push(` * Auto-generated by Phase 144 -- QA Ladder V2`);
  lines.push(` * Domain: ${domain}`);
  lines.push(` * Phases: ${phases.map((p) => p.phaseNumber).join(', ')}`);
  lines.push(` *`);
  lines.push(` * DO NOT EDIT MANUALLY -- regenerate with:`);
  lines.push(` *   node scripts/qa/generate-phase-tests.mjs`);
  lines.push(` */`);
  lines.push(``);
  lines.push(`import { test, expect } from "@playwright/test";`);
  lines.push(``);
  lines.push(`const API = process.env.API_URL ?? "http://localhost:3001";`);
  lines.push(``);

  for (const phase of phases) {
    const safeTitle = phase.title.replace(/['"\\]/g, '').slice(0, 60);

    // API route reachability (no 500s)
    const apiRoutes = phase.routes.filter(
      (r) =>
        r.startsWith('/') &&
        !r.includes('{') &&
        !r.includes(':') &&
        !r.includes('*') &&
        !r.includes('<')
    );

    // Skip phases that would produce empty describe blocks
    const hasDomainTests =
      (phase.domains.includes('clinical') && apiRoutes.some((r) => r.startsWith('/vista/'))) ||
      (phase.domains.includes('rcm') && apiRoutes.some((r) => r.startsWith('/rcm/'))) ||
      (phase.domains.includes('intake') && apiRoutes.some((r) => r.startsWith('/intake/'))) ||
      (phase.domains.includes('scheduling') && apiRoutes.some((r) => r.startsWith('/scheduling/')));

    if (apiRoutes.length === 0 && phase.uiComponents.length === 0 && !hasDomainTests) {
      continue; // No testable surface for this phase
    }

    lines.push(`test.describe("Phase ${phase.phaseNumber}: ${safeTitle}", () => {`);

    if (apiRoutes.length > 0) {
      lines.push(`  test("API routes respond without 500", async ({ request }) => {`);
      for (const route of apiRoutes.slice(0, 6)) {
        const varName = `r_${safeId(route)}`;
        lines.push(`    const ${varName} = await request.get(\`\${API}${route}\`);`);
        lines.push(`    expect(${varName}.status(), "${route} should not be 500").not.toBe(500);`);
      }
      lines.push(`  });`);
      lines.push(``);
    }

    // Integration-pending compliance
    if (apiRoutes.length > 0) {
      lines.push(
        `  test("integration-pending responses include nextSteps", async ({ request }) => {`
      );
      const route = apiRoutes[0];
      lines.push(`    const res = await request.get(\`\${API}${route}\`);`);
      lines.push(`    if (res.status() === 200) {`);
      lines.push(`      const body = await res.json().catch(() => null);`);
      lines.push(`      if (body?.status === "integration-pending") {`);
      lines.push(`        expect(body).toHaveProperty("nextSteps");`);
      lines.push(`        expect(body).toHaveProperty("vistaGrounding");`);
      lines.push(`      }`);
      lines.push(`    }`);
      lines.push(`  });`);
      lines.push(``);
    }

    // UI component file existence
    if (phase.uiComponents.length > 0) {
      lines.push(`  test("UI component files exist", async () => {`);
      lines.push(`    const { readdirSync } = await import("node:fs");`);
      lines.push(`    const { join, resolve: resolvePath } = await import("node:path");`);
      lines.push(`    const root = resolvePath(__dirname, "..", "..", "..", "..");`);
      lines.push(`    const componentNames = ${JSON.stringify(phase.uiComponents.slice(0, 8))};`);
      lines.push(`    function findFile(dir: string, name: string, depth = 0): boolean {`);
      lines.push(`      if (depth > 6) return false;`);
      lines.push(`      try {`);
      lines.push(`        for (const entry of readdirSync(dir, { withFileTypes: true })) {`);
      lines.push(`          if (entry.isFile() && entry.name === name) return true;`);
      lines.push(
        `          if (entry.isDirectory() && !entry.name.startsWith(".") && entry.name !== "node_modules") {`
      );
      lines.push(`            if (findFile(join(dir, entry.name), name, depth + 1)) return true;`);
      lines.push(`          }`);
      lines.push(`        }`);
      lines.push(`      } catch { /* skip */ }`);
      lines.push(`      return false;`);
      lines.push(`    }`);
      lines.push(`    let found = 0;`);
      lines.push(`    for (const name of componentNames) {`);
      lines.push(`      if (findFile(join(root, "apps"), name)) found++;`);
      lines.push(`    }`);
      lines.push(`    expect(found).toBeGreaterThan(0);`);
      lines.push(`  });`);
      lines.push(``);
    }

    // Domain-specific journey tests
    if (phase.domains.includes('clinical') && apiRoutes.some((r) => r.startsWith('/vista/'))) {
      lines.push(`  test("clinical data contract shape", async ({ request }) => {`);
      const clinRoute = apiRoutes.find((r) => r.startsWith('/vista/')) || apiRoutes[0];
      lines.push(`    const res = await request.get(\`\${API}${clinRoute}\`);`);
      lines.push(`    // Should return JSON with ok field (may be 401 without auth)`);
      lines.push(`    if (res.status() === 200) {`);
      lines.push(`      const body = await res.json();`);
      lines.push(`      expect(body).toHaveProperty("ok");`);
      lines.push(`    } else {`);
      lines.push(`      expect([401, 403]).toContain(res.status());`);
      lines.push(`    }`);
      lines.push(`  });`);
      lines.push(``);
    }

    if (phase.domains.includes('rcm') && apiRoutes.some((r) => r.startsWith('/rcm/'))) {
      lines.push(`  test("RCM endpoint contract", async ({ request }) => {`);
      const rcmRoute = apiRoutes.find((r) => r.startsWith('/rcm/')) || apiRoutes[0];
      lines.push(`    const res = await request.get(\`\${API}${rcmRoute}\`);`);
      lines.push(`    expect([200, 401, 403]).toContain(res.status());`);
      lines.push(`    if (res.status() === 200) {`);
      lines.push(`      const body = await res.json().catch(() => null);`);
      lines.push(`      if (body) expect(body).toHaveProperty("ok");`);
      lines.push(`    }`);
      lines.push(`  });`);
      lines.push(``);
    }

    if (phase.domains.includes('intake') && apiRoutes.some((r) => r.startsWith('/intake/'))) {
      lines.push(`  test("intake endpoint contract", async ({ request }) => {`);
      const intakeRoute = apiRoutes.find((r) => r.startsWith('/intake/')) || apiRoutes[0];
      lines.push(`    const res = await request.get(\`\${API}${intakeRoute}\`);`);
      lines.push(`    // Intake routes use own auth -- may be 401 without session`);
      lines.push(`    expect([200, 401, 403]).toContain(res.status());`);
      lines.push(`  });`);
      lines.push(``);
    }

    if (
      phase.domains.includes('scheduling') &&
      apiRoutes.some((r) => r.startsWith('/scheduling/'))
    ) {
      lines.push(`  test("scheduling endpoint contract", async ({ request }) => {`);
      const schedRoute = apiRoutes.find((r) => r.startsWith('/scheduling/')) || apiRoutes[0];
      lines.push(`    const res = await request.get(\`\${API}${schedRoute}\`);`);
      lines.push(`    expect([200, 401, 403]).toContain(res.status());`);
      lines.push(`  });`);
      lines.push(``);
    }

    lines.push(`});`);
    lines.push(``);
  }

  return lines.join('\n');
}

// -- RPC Replay Test Generator --

function generateRpcReplayTests(phases, goldenTrace) {
  const lines = [];
  lines.push(`/**`);
  lines.push(` * Auto-generated by Phase 144 -- QA Ladder V2`);
  lines.push(` * RPC Golden Trace Replay Tests`);
  lines.push(` *`);
  lines.push(` * Validates that RPC sequences match the golden baseline.`);
  lines.push(` * If VistA is unavailable, tests are skipped (integration_pending).`);
  lines.push(` *`);
  lines.push(` * DO NOT EDIT MANUALLY -- regenerate with:`);
  lines.push(` *   node scripts/qa/generate-phase-tests.mjs`);
  lines.push(` */`);
  lines.push(``);
  lines.push(`import { describe, it, expect, beforeAll } from "vitest";`);
  lines.push(`import { readFileSync, existsSync } from "node:fs";`);
  lines.push(`import { resolve } from "node:path";`);
  lines.push(``);
  lines.push(`const API = process.env.API_URL ?? "http://localhost:3001";`);
  lines.push(`const TRACE_PATH = resolve(__dirname, "../fixtures/rpc-golden-trace.json");`);
  lines.push(``);
  lines.push(`let vistaAvailable = false;`);
  lines.push(`let goldenTrace: any = null;`);
  lines.push(``);
  lines.push(`beforeAll(async () => {`);
  lines.push(`  // Check VistA availability`);
  lines.push(`  try {`);
  lines.push(`    const res = await fetch(\`\${API}/vista/ping\`);`);
  lines.push(`    vistaAvailable = res.status === 200;`);
  lines.push(`  } catch { vistaAvailable = false; }`);
  lines.push(``);
  lines.push(`  // Load golden trace`);
  lines.push(`  if (existsSync(TRACE_PATH)) {`);
  lines.push(`    const raw = readFileSync(TRACE_PATH, "utf-8");`);
  lines.push(`    goldenTrace = JSON.parse(raw.charCodeAt(0) === 0xfeff ? raw.slice(1) : raw);`);
  lines.push(`  }`);
  lines.push(`});`);
  lines.push(``);

  // Collect all unique RPC workflows referenced by the selected phases
  const workflowsUsed = new Set();
  for (const p of phases) {
    for (const wf of p.rpcWorkflows) {
      workflowsUsed.add(wf);
    }
  }

  lines.push(`describe("RPC Golden Trace Replay", () => {`);
  lines.push(`  it("golden trace file exists and is valid", () => {`);
  lines.push(`    expect(goldenTrace, "Golden trace file should exist").toBeTruthy();`);
  lines.push(`    expect(goldenTrace).toHaveProperty("workflows");`);
  lines.push(`    expect(goldenTrace).toHaveProperty("registrySnapshot");`);
  lines.push(`  });`);
  lines.push(``);

  // Per-workflow replay tests
  if (goldenTrace) {
    try {
      const trace = goldenTrace;

      for (const [wfName, wfData] of Object.entries(trace.workflows)) {
        if (workflowsUsed.size > 0 && !workflowsUsed.has(wfName)) continue;
        const rpcs = wfData.rpcSequence;

        lines.push(
          `  it.skipIf(!vistaAvailable)("workflow: ${wfName} -- ${rpcs.length} RPCs in sequence", () => {`
        );
        lines.push(`    const wf = goldenTrace?.workflows?.["${wfName}"];`);
        lines.push(`    expect(wf, "Workflow ${wfName} must exist in golden trace").toBeTruthy();`);
        lines.push(`    expect(wf.rpcSequence).toEqual(${JSON.stringify(rpcs)});`);
        lines.push(`  });`);
        lines.push(``);
      }

      // Registry snapshot validation
      if (trace.registrySnapshot?.criticalRpcs) {
        lines.push(`  it("critical RPCs remain in registry snapshot", () => {`);
        lines.push(`    const expected = ${JSON.stringify(trace.registrySnapshot.criticalRpcs)};`);
        lines.push(`    const actual = goldenTrace?.registrySnapshot?.criticalRpcs ?? [];`);
        lines.push(`    for (const rpc of expected) {`);
        lines.push(`      expect(actual, \`Missing critical RPC: \${rpc}\`).toContain(rpc);`);
        lines.push(`    }`);
        lines.push(`  });`);
        lines.push(``);
      }
    } catch {
      lines.push(`  it("golden trace file is parseable", () => {`);
      lines.push(`    expect(goldenTrace).toBeTruthy();`);
      lines.push(`  });`);
    }
  }

  lines.push(`  it("no PHI in golden trace", () => {`);
  lines.push(`    const text = JSON.stringify(goldenTrace);`);
  lines.push(`    expect(text).not.toMatch(/\\b\\d{3}-\\d{2}-\\d{4}\\b/); // SSN`);
  lines.push(`    expect(text).not.toMatch(/\\b\\d{2}\\/\\d{2}\\/\\d{4}\\b/); // DOB mm/dd/yyyy`);
  lines.push(`    expect(text.toLowerCase()).not.toContain("password");`);
  lines.push(`  });`);

  lines.push(`});`);
  lines.push(``);

  // Phase-specific RPC coverage
  const traceWorkflowNames = goldenTrace ? Object.keys(goldenTrace.workflows || {}) : [];
  lines.push(`describe("Phase RPC Coverage", () => {`);
  for (const p of phases.filter((ph) => ph.rpcWorkflows.length > 0)) {
    // Only assert workflows that exist in the golden trace
    const coveredWfs = p.rpcWorkflows.filter((wf) => traceWorkflowNames.includes(wf));
    const uncoveredWfs = p.rpcWorkflows.filter((wf) => !traceWorkflowNames.includes(wf));

    if (coveredWfs.length > 0) {
      lines.push(
        `  it("Phase ${p.phaseNumber} RPC workflows covered: ${coveredWfs.join(', ')}", () => {`
      );
      lines.push(`    const workflows = ${JSON.stringify(coveredWfs)};`);
      lines.push(`    for (const wf of workflows) {`);
      lines.push(
        `      expect(goldenTrace?.workflows, \`Workflow \${wf} missing from golden trace\`).toHaveProperty(wf);`
      );
      lines.push(`    }`);
      lines.push(`  });`);
      lines.push(``);
    }

    if (uncoveredWfs.length > 0) {
      lines.push(
        `  it("Phase ${p.phaseNumber} workflows pending trace: ${uncoveredWfs.join(', ')}", () => {`
      );
      lines.push(
        `    // These workflows are mapped by the phase registry but not yet in the golden trace.`
      );
      lines.push(`    // Add them to rpc-golden-trace.json when the RPCs are integrated.`);
      lines.push(`    const pending = ${JSON.stringify(uncoveredWfs)};`);
      lines.push(`    for (const wf of pending) {`);
      lines.push(`      if (goldenTrace?.workflows?.[wf]) {`);
      lines.push(`        expect(goldenTrace.workflows[wf]).toHaveProperty("rpcSequence");`);
      lines.push(`      }`);
      lines.push(`    }`);
      lines.push(`  });`);
      lines.push(``);
    }
  }
  lines.push(`});`);

  return lines.join('\n');
}

// -- Restart Resilience Generator --

function generateRestartResilienceTests(phases) {
  const lines = [];
  lines.push(`/**`);
  lines.push(` * Auto-generated by Phase 144 -- QA Ladder V2`);
  lines.push(` * Restart Resilience Tests`);
  lines.push(` *`);
  lines.push(` * Validates that durable stores and critical data survive`);
  lines.push(` * across API restarts. Tests the contracts, not actual restarts.`);
  lines.push(` *`);
  lines.push(` * DO NOT EDIT MANUALLY -- regenerate with:`);
  lines.push(` *   node scripts/qa/generate-phase-tests.mjs`);
  lines.push(` */`);
  lines.push(``);
  lines.push(`import { describe, it, expect, beforeAll } from "vitest";`);
  lines.push(``);
  lines.push(`const API = process.env.API_URL ?? "http://localhost:3001";`);
  lines.push(``);
  lines.push(`let apiAvailable = false;`);
  lines.push(``);
  lines.push(`beforeAll(async () => {`);
  lines.push(`  try {`);
  lines.push(`    const res = await fetch(\`\${API}/health\`);`);
  lines.push(`    apiAvailable = res.status === 200;`);
  lines.push(`  } catch { apiAvailable = false; }`);
  lines.push(`});`);
  lines.push(``);

  // Group phases by their store dependencies
  const storePhases = new Map();
  for (const p of phases) {
    for (const store of p.stores) {
      if (!storePhases.has(store)) storePhases.set(store, []);
      storePhases.get(store).push(p);
    }
  }

  lines.push(`describe("Restart Resilience", () => {`);

  // Health endpoint contract
  lines.push(`  it("health endpoint responds after startup", async () => {`);
  lines.push(`    if (!apiAvailable) return;`);
  lines.push(`    const res = await fetch(\`\${API}/health\`);`);
  lines.push(`    expect(res.status).toBe(200);`);
  lines.push(`    const body = await res.json();`);
  lines.push(`    expect(body).toHaveProperty("ok", true);`);
  lines.push(`    expect(body).toHaveProperty("uptime");`);
  lines.push(`  });`);
  lines.push(``);

  // Ready endpoint (circuit breaker state)
  lines.push(`  it("ready endpoint reflects circuit breaker state", async () => {`);
  lines.push(`    if (!apiAvailable) return;`);
  lines.push(`    const res = await fetch(\`\${API}/ready\`);`);
  lines.push(`    expect(res.status).toBe(200);`);
  lines.push(`    const body = await res.json();`);
  lines.push(`    expect(body).toHaveProperty("ok");`);
  lines.push(`  });`);
  lines.push(``);

  // Per-store resilience tests
  const STORES_WITH_TESTS = [
    'platform-db',
    'pg',
    'session-store',
    'claim-store',
    'immutable-audit',
    'brain-registry',
  ];
  for (const [store, storePs] of storePhases) {
    const phaseList = storePs.map((p) => p.phaseNumber).join(', ');
    lines.push(`  describe("Store: ${store} (Phases ${phaseList})", () => {`);

    if (store === 'platform-db' || store === 'pg') {
      lines.push(`    it("database connection is healthy", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(`      const res = await fetch(\`\${API}/health\`);`);
      lines.push(`      const body = await res.json();`);
      lines.push(`      expect(body.ok).toBe(true);`);
      lines.push(`    });`);
    }

    if (store === 'session-store') {
      lines.push(`    it("session store accepts new sessions", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(`      const ac = process.env.VISTA_ACCESS_CODE || "test";`);
      lines.push(`      const vc = process.env.VISTA_VERIFY_CODE || "test";`);
      lines.push(`      const res = await fetch(\`\${API}/auth/login\`, {`);
      lines.push(`        method: "POST",`);
      lines.push(`        headers: { "Content-Type": "application/json" },`);
      lines.push(`        body: JSON.stringify({ accessCode: ac, verifyCode: vc }),`);
      lines.push(`      });`);
      lines.push(
        `      // 200 = success, 401 = bad creds, 503 = VistA down, all valid contract responses`
      );
      lines.push(`      expect([200, 401, 503]).toContain(res.status);`);
      lines.push(`    });`);
    }

    if (store === 'claim-store') {
      lines.push(`    it("claim store endpoints respond (may require auth)", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(`      const res = await fetch(\`\${API}/rcm/claims\`);`);
      lines.push(`      expect([200, 401, 403]).toContain(res.status);`);
      lines.push(`    });`);
    }

    if (store === 'immutable-audit') {
      lines.push(`    it("audit verify endpoint responds", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(`      const res = await fetch(\`\${API}/iam/audit/verify\`);`);
      lines.push(`      expect([200, 401, 403]).toContain(res.status);`);
      lines.push(`    });`);
    }

    if (store === 'brain-registry') {
      lines.push(`    it("brain provider registry responds after restart", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(`      const res = await fetch(\`\${API}/intake/providers\`);`);
      lines.push(`      expect([200, 401]).toContain(res.status);`);
      lines.push(`    });`);
    }

    // Fallback test for stores without specific assertions
    if (!STORES_WITH_TESTS.includes(store)) {
      lines.push(`    it("in-memory store reinitializes on restart (${store})", async () => {`);
      lines.push(`      if (!apiAvailable) return;`);
      lines.push(
        `      // In-memory stores reset on restart -- health endpoint confirms API is live`
      );
      lines.push(`      const res = await fetch(\`\${API}/health\`);`);
      lines.push(`      expect(res.status).toBe(200);`);
      lines.push(`    });`);
    }

    lines.push(`  });`);
    lines.push(``);
  }

  // Error shape during degraded state
  lines.push(`  it("error responses are well-shaped JSON", async () => {`);
  lines.push(`    if (!apiAvailable) return;`);
  lines.push(`    const res = await fetch(\`\${API}/nonexistent-route-for-test\`);`);
  lines.push(`    expect(res.status).toBe(404);`);
  lines.push(`    const body = await res.json().catch(() => null);`);
  lines.push(`    // Should be JSON, not raw HTML or stack trace`);
  lines.push(`    expect(body).not.toBeNull();`);
  lines.push(`  });`);
  lines.push(``);

  // Concurrent request resilience
  lines.push(`  it("handles concurrent requests without crash", async () => {`);
  lines.push(`    if (!apiAvailable) return;`);
  lines.push(`    const requests = Array.from({ length: 10 }, () =>`);
  lines.push(`      fetch(\`\${API}/health\`).then((r) => r.status).catch(() => 0)`);
  lines.push(`    );`);
  lines.push(`    const results = await Promise.all(requests);`);
  lines.push(`    const successful = results.filter((s) => s === 200).length;`);
  lines.push(`    expect(successful).toBeGreaterThanOrEqual(8);`);
  lines.push(`  });`);

  lines.push(`});`);

  return lines.join('\n');
}

// -- Main --

console.log(`\n=== QA Ladder V2 Test Generator (Phase 144) ===\n`);

// Build enriched registry
const registry = buildRegistry();
let phases = registry.phases;

// Apply filters
if (phaseRangeArg) {
  const [from, to] = phaseRangeArg.split('-').map(Number);
  phases = phases.filter((p) => {
    const n = parseInt(p.phaseNumber);
    return n >= from && n <= to;
  });
  console.log(`  Phase filter: ${from}-${to} (${phases.length} phases matched)`);
}

if (domainFilter) {
  phases = phases.filter((p) => p.domains.includes(domainFilter));
  console.log(`  Domain filter: ${domainFilter} (${phases.length} phases matched)`);
}

if (phases.length === 0) {
  console.log('  No phases matched. Exiting.');
  process.exit(0);
}

// Ensure output dirs
for (const dir of [E2E_DIR, RPC_DIR, RESTART_DIR]) {
  mkdirSync(dir, { recursive: true });
}

// Clean previously generated files
cleanDir(E2E_DIR, 'domain-');
cleanDir(RPC_DIR, 'rpc-replay');
cleanDir(RESTART_DIR, 'restart-');

let filesWritten = 0;

// -- 1. Playwright Domain Journeys --

const domainGroups = new Map();
for (const p of phases) {
  for (const d of p.domains) {
    if (!domainGroups.has(d)) domainGroups.set(d, []);
    domainGroups.get(d).push(p);
  }
}

for (const [domain, domainPhases] of domainGroups) {
  // Skip domains with no testable routes
  if (domainPhases.every((p) => p.routes.length === 0 && p.uiComponents.length === 0)) continue;

  const content = generatePlaywrightJourney(domain, domainPhases);
  const filePath = join(E2E_DIR, `domain-${domain}.spec.ts`);

  if (DRY_RUN) {
    console.log(`  [DRY] ${filePath} (${domainPhases.length} phases)`);
  } else {
    writeFileSync(filePath, content);
    console.log(`  WROTE  ${filePath.replace(ROOT, '.')} (${domainPhases.length} phases)`);
    filesWritten++;
  }
}

// -- 2. RPC Replay Tests --

const rpcPhases = phases.filter((p) => p.rpcWorkflows.length > 0);
if (rpcPhases.length > 0) {
  // Load golden trace so per-workflow replay tests are generated
  const GOLDEN_TRACE_PATH = join(ROOT, 'apps/api/tests/fixtures/rpc-golden-trace.json');
  let loadedTrace = null;
  if (existsSync(GOLDEN_TRACE_PATH)) {
    try {
      const raw = readFileSync(GOLDEN_TRACE_PATH, 'utf-8');
      loadedTrace = JSON.parse(raw.charCodeAt(0) === 0xfeff ? raw.slice(1) : raw);
    } catch {
      /* trace file unparseable, tests will still get structural validation */
    }
  }
  const content = generateRpcReplayTests(rpcPhases, loadedTrace);
  const filePath = join(RPC_DIR, 'rpc-replay-golden.test.ts');

  if (DRY_RUN) {
    console.log(`  [DRY] ${filePath} (${rpcPhases.length} phases)`);
  } else {
    writeFileSync(filePath, content);
    console.log(`  WROTE  ${filePath.replace(ROOT, '.')} (${rpcPhases.length} phases)`);
    filesWritten++;
  }
}

// -- 3. Restart Resilience Tests --

const restartPhases = phases.filter((p) => p.stores.length > 0);
if (restartPhases.length > 0) {
  const content = generateRestartResilienceTests(restartPhases);
  const filePath = join(RESTART_DIR, 'restart-resilience.test.ts');

  if (DRY_RUN) {
    console.log(`  [DRY] ${filePath} (${restartPhases.length} phases)`);
  } else {
    writeFileSync(filePath, content);
    console.log(`  WROTE  ${filePath.replace(ROOT, '.')} (${restartPhases.length} phases)`);
    filesWritten++;
  }
}

// -- Summary --

console.log(`\n  Summary:`);
console.log(`    Phases processed: ${phases.length}`);
console.log(`    Files written: ${filesWritten}`);
console.log(`    Domain journeys: ${domainGroups.size}`);
console.log(`    RPC replay phases: ${rpcPhases.length}`);
console.log(`    Restart phases: ${restartPhases.length}`);
console.log(``);
